import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"PRD-009 — Mars Surface Map","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-009.md","filePath":"prd/PRD-009.md"}'),o={name:"prd/PRD-009.md"};function r(n,e,l,d,c,h){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="prd-009-—-mars-surface-map" tabindex="-1">PRD-009 — Mars Surface Map <a class="header-anchor" href="#prd-009-—-mars-surface-map" aria-label="Permalink to &quot;PRD-009 — Mars Surface Map&quot;">​</a></h1><p><em>Orrery · Product Requirements · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Draft <strong>Sources:</strong> PRD-006 (Moon Map) as the established pattern; mission catalogue Mars subset <strong>Audiences:</strong> curious learner, STEM student, space enthusiast (PA §audiences) <strong>Promises:</strong> real mission data fully attributed, educational at every level (PA §promises) <strong>Principles:</strong> physics first, attribution is design (PA §principles) <strong>Why this is a PRD:</strong> Orrery&#39;s thesis is &quot;Mars&quot; — and yet today the only Mars surface representation is a textual list inside the mission library. The Moon Map (PRD-006) proves the spatial-anchor pattern works. A peer Mars Map closes the loop: every artefact humanity has placed on Mars, situated on a 3D globe, with full mission context one click away.</p></blockquote><p>A student rotating the 3D Mars globe finds Jezero Crater. The label reads: &quot;Perseverance, 2021 — searching for biosignatures in an ancient lake delta.&quot; They click the site. The panel opens with the rover&#39;s payload, sample-cache locations, what&#39;s been found so far. They rotate west to find Curiosity at Gale Crater. The capability connection is written into the panels: each rover in the lineage extending what the previous one proved.</p><hr><h2 id="§why" tabindex="-1">§why <a class="header-anchor" href="#§why" aria-label="Permalink to &quot;§why&quot;">​</a></h2><p>The Moon Map gave Orrery a spatial home for the lunar artefact catalogue. Mars deserves the same. Today&#39;s <code>/missions</code> page lists every Mars mission as a card, but <strong>lists are not maps</strong>. The user cannot see at a glance:</p><ul><li>That every successful landing has been on the equatorial plain or near it (latitude bias of EDL physics).</li><li>That Perseverance and Curiosity are &lt;4000 km apart on a planet that&#39;s twice the size of the Moon.</li><li>That every Soviet attempt landed in a tight band of equatorial longitudes.</li><li>That the Phoenix and InSight landers sit far north of all the rovers — chosen for ice (Phoenix) and quiet seismology (InSight) respectively.</li></ul><p>A spatial view makes the engineering history of Mars surface operations <em>visible</em>. It also gives the simulator a satisfying symmetry: same UX pattern, same data shape, same panel structure as Moon — but Mars-flavoured.</p><hr><h2 id="§audiences" tabindex="-1">§audiences <a class="header-anchor" href="#§audiences" aria-label="Permalink to &quot;§audiences&quot;">​</a></h2><p><strong>The curious learner</strong> rotates the 3D globe to see where each rover landed and discovers Mars&#39;s geographic story (Tharsis, Hellas, Vastitas Borealis) by reading the labels of the artefacts placed within each region.</p><p><strong>The STEM student</strong> uses the page to ground the orbital-arrival data on /fly + /missions in physical geography. &quot;Curiosity arrived October 2012, landing site 4.59°S, 137.44°E&quot; — the surface map shows them what those coordinates <em>mean</em>.</p><p><strong>The space enthusiast</strong> uses it as a reference for the full landed inventory — every successful landing, every failed lander where the wreckage was located by orbiters, every active rover and its current location.</p><hr><h2 id="§promises" tabindex="-1">§promises <a class="header-anchor" href="#§promises" aria-label="Permalink to &quot;§promises&quot;">​</a></h2><ol><li><strong>Every artefact humanity has put on Mars is plotted.</strong> Successful landings, failed landings whose location is known, and inactive hardware that&#39;s still there. The data set is finite (currently ~30 entries) so completeness is achievable.</li><li><strong>Every site has a panel matching the Moon-site panel.</strong> OVERVIEW · GALLERY · LEARN tabs. Same component, same tokens, same accessibility contract.</li><li><strong>Every site cross-links to the mission card</strong> in <code>/missions</code>. Tapping a site can navigate to the corresponding mission&#39;s detail. The site IS the mission&#39;s surface footprint.</li><li><strong>3D globe + 2D flat map.</strong> Same toggle pattern as <code>/moon</code>.</li><li><strong>Locale-aware</strong> per ADR-017.</li></ol><hr><h2 id="§scope" tabindex="-1">§scope <a class="header-anchor" href="#§scope" aria-label="Permalink to &quot;§scope&quot;">​</a></h2><h3 id="in-scope-v1" tabindex="-1">In scope (V1) <a class="header-anchor" href="#in-scope-v1" aria-label="Permalink to &quot;In scope (V1)&quot;">​</a></h3><p><strong>Default view: 3D Mars globe.</strong></p><ul><li>Mars textured sphere, slow rotation by default (matches /moon).</li><li>Tilt: 25° axial tilt (matches actual Mars obliquity for educational accuracy).</li><li>Landing sites as crosshair markers, agency-coloured.</li><li>Hover: tooltip with mission name + year.</li><li>Click: opens detail panel.</li></ul><p><strong>2D flat map toggle.</strong></p><ul><li>Equirectangular projection of Mars, matching the prototype convention.</li><li>Same markers, same panel.</li><li>Reveals lat/lon clustering at a glance — the equatorial-EDL bias becomes visible.</li></ul><p><strong>Sites to plot (V1 list).</strong> All artefacts with confirmed surface locations:</p><table tabindex="0"><thead><tr><th>Mission</th><th>Year</th><th>Nation</th><th>Status</th><th>Lat / Lon</th></tr></thead><tbody><tr><td>Mars 2 lander</td><td>1971</td><td>USSR</td><td>Crashed</td><td>45°S 313°E (approx.)</td></tr><tr><td>Mars 3 lander</td><td>1971</td><td>USSR</td><td>Partial — 14.5 s of data</td><td>45°S 158°W</td></tr><tr><td>Mars 6</td><td>1973</td><td>USSR</td><td>Comm-loss before landing</td><td>23.9°S 19.4°W</td></tr><tr><td>Viking 1</td><td>1976</td><td>USA</td><td>Successful</td><td>22.27°N 312.05°E</td></tr><tr><td>Viking 2</td><td>1976</td><td>USA</td><td>Successful</td><td>47.97°N 134.0°E</td></tr><tr><td>Mars Pathfinder + Sojourner</td><td>1997</td><td>USA</td><td>Successful (rover)</td><td>19.13°N 33.22°W</td></tr><tr><td>Beagle 2</td><td>2003</td><td>UK / ESA</td><td>Lost on landing; located 2015 by MRO</td><td>11.53°N 90.43°E</td></tr><tr><td>Spirit</td><td>2004</td><td>USA</td><td>Successful (rover)</td><td>14.57°S 175.47°E</td></tr><tr><td>Opportunity</td><td>2004</td><td>USA</td><td>Successful (rover)</td><td>1.95°S 354.47°E</td></tr><tr><td>Phoenix</td><td>2008</td><td>USA</td><td>Successful (lander)</td><td>68.22°N 234.25°E</td></tr><tr><td>Curiosity</td><td>2012</td><td>USA</td><td>Active (rover)</td><td>4.59°S 137.44°E</td></tr><tr><td>Schiaparelli</td><td>2016</td><td>ESA / Roscosmos</td><td>Crashed</td><td>2.07°S 6.21°E</td></tr><tr><td>InSight</td><td>2018</td><td>USA</td><td>Mission complete (lander)</td><td>4.5°N 135.62°E</td></tr><tr><td>Perseverance + Ingenuity</td><td>2021</td><td>USA</td><td>Active (rover + helicopter)</td><td>18.44°N 77.45°E</td></tr><tr><td>Tianwen-1 + Zhurong</td><td>2021</td><td>China</td><td>Mission complete (rover)</td><td>25.1°N 109.93°E</td></tr><tr><td>ExoMars Rosalind Franklin</td><td>TBD (PLANNED)</td><td>ESA</td><td>Planned 2028+</td><td>TBD</td></tr></tbody></table><p>≈ 16 sites for V1.</p><p><strong>Panel structure</strong> (mirrors <code>/moon</code>):</p><ul><li><strong>OVERVIEW</strong> — agency, mission name, year, lat/lon, outcome (<code>SUCCESS / CRASHED / LOST / ACTIVE / PLANNED</code>), short description, capability-ladder line (&quot;first to X&quot;).</li><li><strong>GALLERY</strong> — surface photos. Mars-mission photo manifests already exist (NASA&#39;s MSL/MER/Pathfinder image catalogues are vast). 4–8 photos per site.</li><li><strong>LEARN</strong> — INTRO / CORE / DEEP tiered links per ADR-017 / PRD-006 extension. NASA mission pages (core), Wikipedia primers (intro), peer-reviewed surface-science papers (deep).</li><li><strong>&quot;Still on the surface&quot; footer</strong> for inactive missions — what&#39;s physically left at the site (lander hull, descent stage, etc.).</li><li><strong>&quot;FLY THIS MISSION&quot;</strong> button when the mission has flight data (deep-link to <code>/fly?mission=[id]</code>). Symmetric with /moon and /missions.</li></ul><p><strong>3D globe interaction.</strong></p><ul><li>Single-finger drag → rotate.</li><li>Two-finger pinch → zoom (clamped 0.6× → 4×).</li><li>Tap a marker → opens panel.</li><li>Pulsating ring around the active marker if a panel is open.</li></ul><p><strong>2D flat-map interaction.</strong></p><ul><li>Tap a marker → opens panel.</li><li>Pinch / scroll → zoom (clamped same range).</li><li>Two-finger drag → pan (when zoomed).</li></ul><h3 id="out-of-scope-v1" tabindex="-1">Out of scope (V1) <a class="header-anchor" href="#out-of-scope-v1" aria-label="Permalink to &quot;Out of scope (V1)&quot;">​</a></h3><ul><li>Mars regional features (Olympus Mons, Valles Marineris, etc.) as labelled features. They appear in the texture but aren&#39;t clickable.</li><li>Real-time rover position (Curiosity and Perseverance do move — V1 plots their landing site, not their current position).</li><li>Mission planning context (porkchop / arrival window) — that&#39;s <code>/plan</code>&#39;s job.</li><li>Polar-projection toggle (the prototype experiments with this on Moon — defer for Mars V1).</li><li>Routes traversed by rovers (would be a beautiful V2 feature but adds significant data + visual complexity).</li><li>Failed missions whose location is <em>not</em> known (e.g. Mars Climate Orbiter — never reached the surface).</li></ul><hr><h2 id="§design-hints" tabindex="-1">§design hints <a class="header-anchor" href="#§design-hints" aria-label="Permalink to &quot;§design hints&quot;">​</a></h2><p><strong>Layout.</strong> Same chrome as <code>/moon</code>:</p><ul><li>3D / 2D toggle top-right (matches /explore pattern after the v0.4 HUD reorganisation).</li><li>Nation legend bottom — <code>USA · USSR/Russia · ESA · China · UK · India</code> agency-coloured dots. Failed-attempt sites get a thin striped border so success/failure is visible without opening the panel.</li><li>Detail panel: bottom sheet on mobile, right drawer on desktop (per ADR-018).</li></ul><p><strong>Tokens.</strong></p><ul><li>Mars texture: 2K equirectangular <code>2k_mars.jpg</code> (already in <code>static/textures/</code>, used by /explore).</li><li>Marker fill: agency-coloured 6 px disc + 1 px white outline for legibility on red terrain.</li><li>Failed-site marker: same fill, dashed white outline (not striped — keeps the small disc readable).</li><li>Active mission badge in panel header: same green-tint pattern as /missions ACTIVE filter.</li></ul><p><strong>Data flow.</strong></p><ul><li>New file <code>static/data/mars-sites.json</code> (mirrors <code>moon-sites.json</code> schema). Schema validated by ajv (RFC-002 / ADR-019 extension).</li><li>Locale overlays at <code>static/data/i18n/[locale]/mars-sites/[id].json</code>.</li><li>Cross-link to mission cards via shared <code>mission_id</code> field — the same id appears in both <code>mars-sites.json</code> and <code>data/missions/mars/</code>.</li></ul><p><strong>Mobile.</strong> 375 px width without horizontal scroll. 3D globe is full-bleed; toggle and legend overlay.</p><hr><h2 id="§non-goals" tabindex="-1">§non-goals <a class="header-anchor" href="#§non-goals" aria-label="Permalink to &quot;§non-goals&quot;">​</a></h2><ul><li><strong>Not a Mars geography textbook.</strong> No labelled features beyond landing-site markers. Geography emerges from looking at where the markers cluster.</li><li><strong>Not a real-time rover dashboard.</strong> Static landing sites. (Real-time would require a NASA-API integration that is outside the static-asset model per ADR-016.)</li><li><strong>Not duplicating <code>/missions</code>.</strong> A mission card in <code>/missions</code> and a surface site here are two views of the same data. The site links to the card; the card may eventually link back to the site.</li></ul><hr><h2 id="§technical-considerations" tabindex="-1">§technical considerations <a class="header-anchor" href="#§technical-considerations" aria-label="Permalink to &quot;§technical considerations&quot;">​</a></h2><ul><li><strong>Schema reuse.</strong> Extend the existing <code>moon-site.ts</code> type into a generic <code>surface-site.ts</code> (lat, lon, nation, agency, mission_id, year, status, links, etc.). Mars-sites and Moon-sites both implement it. Reduces drift.</li><li><strong>3D rendering.</strong> Three.js r128 — same renderer the rest of the app uses. Sphere mesh + a thin <code>Group</code> of marker meshes layered on the sphere surface. CPU pick on click.</li><li><strong>Texture.</strong> The existing <code>2k_mars.jpg</code> is already cached at build per ADR-016. No new asset fetch.</li><li><strong>Locale flow.</strong> ADR-017 applies as-is.</li><li><strong>Routing.</strong> New route <code>/mars</code> (peer to <code>/moon</code>). URL params: <code>?site=[id]</code> deep-links open with the panel pre-opened.</li><li><strong>Nav reorder.</strong> The current nav order (after the v0.4 update) is <code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → MOON</code>. Adding MARS could go either after MOON (preserves the &quot;by destination&quot; cluster) or before EARTH (preserves the &quot;size order&quot;). UXS-009 to settle.</li></ul><hr><h2 id="§definition-of-done" tabindex="-1">§definition-of-done <a class="header-anchor" href="#§definition-of-done" aria-label="Permalink to &quot;§definition-of-done&quot;">​</a></h2><p>A locale is considered &quot;Mars-shipped&quot; when:</p><ul><li>[ ] All ~16 V1 sites listed in §scope render on both 3D globe and 2D map.</li><li>[ ] Each site has OVERVIEW · GALLERY · LEARN tabs populated.</li><li>[ ] Each site has at least one photo in GALLERY.</li><li>[ ] Each site cross-links to the corresponding mission card if one exists.</li><li>[ ] Failed-attempt sites are visually distinguishable from successful ones.</li><li>[ ] Mobile (375 px) renders without horizontal scroll.</li><li>[ ] No console errors on /mars or any /mars?site=... deep-link.</li><li>[ ] /mars is added to the nav bar in the agreed order.</li><li>[ ] Lighthouse accessibility ≥ 95.</li><li>[ ] E2e: click marker → panel opens; panel close → marker deselects; deep-link <code>/mars?site=curiosity</code> opens the panel pre-selected.</li></ul><hr><h2 id="§what-comes-after" tabindex="-1">§what comes after <a class="header-anchor" href="#§what-comes-after" aria-label="Permalink to &quot;§what comes after&quot;">​</a></h2><p>V1.5+: rover traverses (Curiosity / Perseverance / Opportunity routes as polylines on the surface). V2: real-time current-position overlay (would require a small NASA-API shim that doesn&#39;t violate the offline-first promise — TBD).</p><hr><p><em>Orrery · PRD-009 · Draft v0.1 · Update when scope or definition-of-done changes.</em></p>',59)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
